import React, { useState, useEffect } from "react";
import axios from "../api/axios";

export default function AdminVenues() {
  const [venues, setVenues] = useState([]);
  const [loading, setLoading] = useState(true);
  const [currentPage, setCurrentPage] = useState(1);
  const itemsPerPage = 10;

  // Form states
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingVenue, setEditingVenue] = useState(null);
  const [formData, setFormData] = useState({
    name: "",
    address: "",
    city: "",
    latitude: "",
    longitude: "",
    website: "",
    phone: "",
    description: "",
    capacity: "",
  });

  useEffect(() => {
    fetchVenues();
  }, []);

  const fetchVenues = async () => {
    try {
      setLoading(true);
      const response = await axios.get("/events/venues/");
      // Handle both array and paginated responses
      const venuesData = Array.isArray(response.data) ? response.data : (response.data.results || []);
      setVenues(venuesData);
    } catch (error) {
      console.error("Error fetching venues:", error);
      alert("Failed to load venues");
    } finally {
      setLoading(false);
    }
  };

  const handleInputChange = (e) => {
    const { name, value } = e.target;
    setFormData((prev) => ({
      ...prev,
      [name]: value,
    }));
  };

  const handleCreateVenue = async (e) => {
    e.preventDefault();
    try {
      const payload = {
        name: formData.name,
        address: formData.address,
        city: formData.city,
        website: formData.website || null,
        phone: formData.phone || null,
        description: formData.description || null,
        capacity: formData.capacity ? parseInt(formData.capacity) : null,
      };

      if (formData.latitude) payload.latitude = parseFloat(formData.latitude);
      if (formData.longitude) payload.longitude = parseFloat(formData.longitude);

      if (editingVenue) {
        await axios.put(`/events/venues/${editingVenue.id}/`, payload);
        alert("Venue updated successfully!");
      } else {
        await axios.post("/events/venues/", payload);
        alert("Venue created successfully!");
      }

      setFormData({
        name: "",
        address: "",
        city: "",
        latitude: "",
        longitude: "",
        website: "",
        phone: "",
        description: "",
        capacity: "",
      });
      setIsFormOpen(false);
      setEditingVenue(null);
      fetchVenues();
    } catch (error) {
      console.error("Error saving venue:", error);
      alert("Failed to save venue: " + (error.response?.data?.detail || error.message));
    }
  };

  const handleEditVenue = (venue) => {
    setEditingVenue(venue);
    setFormData({
      name: venue.name,
      address: venue.address,
      city: venue.city,
      latitude: venue.latitude || "",
      longitude: venue.longitude || "",
      website: venue.website || "",
      phone: venue.phone || "",
      description: venue.description || "",
      capacity: venue.capacity || "",
    });
    setIsFormOpen(true);
  };

  const handleDeleteVenue = async (id) => {
    if (!window.confirm("Are you sure you want to delete this venue?")) return;
    try {
      await axios.delete(`/events/venues/${id}/`);
      alert("Venue deleted successfully!");
      fetchVenues();
    } catch (error) {
      console.error("Error deleting venue:", error);
      alert("Failed to delete venue");
    }
  };

  const handleCloseForm = () => {
    setIsFormOpen(false);
    setEditingVenue(null);
    setFormData({
      name: "",
      address: "",
      city: "",
      latitude: "",
      longitude: "",
      website: "",
      phone: "",
      description: "",
      capacity: "",
    });
  };

  // Pagination
  const totalPages = Math.ceil(venues.length / itemsPerPage);
  const startIndex = (currentPage - 1) * itemsPerPage;
  const paginatedVenues = venues.slice(startIndex, startIndex + itemsPerPage);

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="text-gray-400">Loading venues...</div>
      </div>
    );
  }

  return (
    <div className="p-6 bg-gray-900 min-h-screen">
      <div className="mb-6 flex items-center justify-between">
        <h1 className="text-3xl font-bold text-white">Venues</h1>
        <button
          onClick={() => setIsFormOpen(true)}
          className="px-6 py-2 rounded-md font-semibold transition-all"
          style={{ background: "#ff00e0", color: "#fff" }}
          onMouseEnter={(e) => {
            e.currentTarget.style.background = "transparent";
            e.currentTarget.style.color = "#ff00e0";
            e.currentTarget.style.outline = "2px solid #ff00e0";
          }}
          onMouseLeave={(e) => {
            e.currentTarget.style.background = "#ff00e0";
            e.currentTarget.style.color = "#fff";
            e.currentTarget.style.outline = "none";
          }}
        >
          + Create Venue
        </button>
      </div>

      {/* Form Modal */}
      {isFormOpen && (
        <div className="fixed inset-0 bg-black/50 flex items-center justify-center z-50">
          <div className="bg-gray-800 p-6 rounded-lg max-w-2xl w-full mx-4 max-h-[90vh] overflow-y-auto">
            <h2 className="text-2xl font-bold text-white mb-4">
              {editingVenue ? "Edit Venue" : "Create New Venue"}
            </h2>

            <form onSubmit={handleCreateVenue} className="space-y-4">
              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">Venue Name *</label>
                <input
                  type="text"
                  name="name"
                  value={formData.name}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  placeholder="e.g., Central Park Amphitheater"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">Address *</label>
                <input
                  type="text"
                  name="address"
                  value={formData.address}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  placeholder="e.g., 123 Main Street"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">City *</label>
                <input
                  type="text"
                  name="city"
                  value={formData.city}
                  onChange={handleInputChange}
                  required
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  placeholder="e.g., New York"
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-sm font-semibold text-gray-300 mb-1">Latitude</label>
                  <input
                    type="number"
                    name="latitude"
                    value={formData.latitude}
                    onChange={handleInputChange}
                    step="0.0001"
                    className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                    placeholder="e.g., 40.7580"
                  />
                </div>
                <div>
                  <label className="block text-sm font-semibold text-gray-300 mb-1">Longitude</label>
                  <input
                    type="number"
                    name="longitude"
                    value={formData.longitude}
                    onChange={handleInputChange}
                    step="0.0001"
                    className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                    placeholder="e.g., -73.9855"
                  />
                </div>
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">Phone</label>
                <input
                  type="tel"
                  name="phone"
                  value={formData.phone}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  placeholder="e.g., (555) 123-4567"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">Website</label>
                <input
                  type="url"
                  name="website"
                  value={formData.website}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  placeholder="e.g., https://example.com"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">Capacity</label>
                <input
                  type="number"
                  name="capacity"
                  value={formData.capacity}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  placeholder="e.g., 1000"
                />
              </div>

              <div>
                <label className="block text-sm font-semibold text-gray-300 mb-1">Description</label>
                <textarea
                  name="description"
                  value={formData.description}
                  onChange={handleInputChange}
                  className="w-full px-3 py-2 bg-gray-700 text-white rounded-md focus:outline-none"
                  rows="3"
                  placeholder="Describe the venue..."
                />
              </div>

              <div className="flex gap-3 pt-4">
                <button
                  type="submit"
                  className="flex-1 px-4 py-2 rounded-md font-semibold transition-all"
                  style={{ background: "#ff00e0", color: "#fff" }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "transparent";
                    e.currentTarget.style.color = "#ff00e0";
                    e.currentTarget.style.outline = "2px solid #ff00e0";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "#ff00e0";
                    e.currentTarget.style.color = "#fff";
                    e.currentTarget.style.outline = "none";
                  }}
                >
                  {editingVenue ? "Update Venue" : "Create Venue"}
                </button>
                <button
                  type="button"
                  onClick={handleCloseForm}
                  className="flex-1 px-4 py-2 rounded-md font-semibold border-2"
                  style={{ borderColor: "#ff00e0", color: "#ff00e0" }}
                  onMouseEnter={(e) => {
                    e.currentTarget.style.background = "#ff00e0";
                    e.currentTarget.style.color = "#000";
                  }}
                  onMouseLeave={(e) => {
                    e.currentTarget.style.background = "transparent";
                    e.currentTarget.style.color = "#ff00e0";
                  }}
                >
                  Cancel
                </button>
              </div>
            </form>
          </div>
        </div>
      )}

      {/* Venues Table */}
      <div className="overflow-x-auto bg-gray-800 rounded-lg">
        <table className="w-full text-sm text-left text-gray-300">
          <thead className="bg-gray-700 text-gray-200">
            <tr>
              <th className="px-4 py-3">Name</th>
              <th className="px-4 py-3">City</th>
              <th className="px-4 py-3">Address</th>
              <th className="px-4 py-3">Phone</th>
              <th className="px-4 py-3">Capacity</th>
              <th className="px-4 py-3">Actions</th>
            </tr>
          </thead>
          <tbody>
            {paginatedVenues.length > 0 ? (
              paginatedVenues.map((venue) => (
                <tr key={venue.id} className="border-b border-gray-700 hover:bg-gray-700/50">
                  <td className="px-4 py-3 font-semibold">{venue.name}</td>
                  <td className="px-4 py-3">{venue.city}</td>
                  <td className="px-4 py-3">{venue.address}</td>
                  <td className="px-4 py-3">{venue.phone || "-"}</td>
                  <td className="px-4 py-3">{venue.capacity ? venue.capacity.toLocaleString() : "-"}</td>
                  <td className="px-4 py-3 space-x-2">
                    <button
                      onClick={() => handleEditVenue(venue)}
                      className="px-3 py-1 rounded text-white font-semibold transition-all"
                      style={{ background: "#0066cc" }}
                      onMouseEnter={(e) => (e.currentTarget.style.background = "#0052a3")}
                      onMouseLeave={(e) => (e.currentTarget.style.background = "#0066cc")}
                    >
                      Edit
                    </button>
                    <button
                      onClick={() => handleDeleteVenue(venue.id)}
                      className="px-3 py-1 rounded text-white font-semibold transition-all"
                      style={{ background: "#cc0000" }}
                      onMouseEnter={(e) => (e.currentTarget.style.background = "#990000")}
                      onMouseLeave={(e) => (e.currentTarget.style.background = "#cc0000")}
                    >
                      Delete
                    </button>
                  </td>
                </tr>
              ))
            ) : (
              <tr>
                <td colSpan="6" className="px-4 py-6 text-center text-gray-400">
                  No venues found. Create your first venue!
                </td>
              </tr>
            )}
          </tbody>
        </table>
      </div>

      {/* Pagination */}
      <div className="mt-6 flex items-center justify-between text-gray-400 text-sm">
        <div>
          Page {currentPage} of {totalPages || 1} • Showing {paginatedVenues.length} of {venues.length} venues
        </div>
        <div className="flex gap-2">
          <button
            onClick={() => setCurrentPage((p) => Math.max(1, p - 1))}
            disabled={currentPage === 1}
            className="px-4 py-2 rounded-md font-semibold transition-all disabled:opacity-50"
            style={{
              background: currentPage === 1 ? "#333" : "#ff00e0",
              color: currentPage === 1 ? "#666" : "#fff",
            }}
          >
            ← Previous
          </button>
          <button
            onClick={() => setCurrentPage((p) => Math.min(totalPages, p + 1))}
            disabled={currentPage === totalPages}
            className="px-4 py-2 rounded-md font-semibold transition-all disabled:opacity-50"
            style={{
              background: currentPage === totalPages ? "#333" : "#ff00e0",
              color: currentPage === totalPages ? "#666" : "#fff",
            }}
          >
            Next →
          </button>
        </div>
      </div>
    </div>
  );
}
